problem:
Trace the execution of the following recursive function and determine its output when called with f(5):
int f(int n) {
    if (n <= 1) return 1;
    return f(n-1) + 2*f(n-2);
}

Given the recursive function below, trace its execution for g(4, 2) and determine the final return value:
int g(int x, int y) {
    if (y == 0) return 1;
    if (x == 0) return 0;
    return g(x-1, y) + g(x, y-1);
}

Trace the recursive function h(6) and determine what value it returns:
int h(int n) {
    if (n < 3) return n;
    return h(n-1) + h(n-2) + h(n-3);
}

Analyze the following recursive function and determine what it computes when called with mystery(12345):
int mystery(int n) {
    if (n < 10) return n;
    return (n % 10) + mystery(n / 10);
}

Trace the execution of recursive function p(5) and determine its output:
int p(int n) {
    if (n <= 0) return 0;
    return n + p(n/2);
}

Given the recursive function below, trace q(7) and determine what value it returns:
int q(int n) {
    if (n <= 1) return 1;
    if (n % 2 == 0) return q(n/2) + 1;
    return q(3*n + 1) + 1;
}

Trace the execution of recursive function r('abcde') and determine what string it returns:
string r(string s) {
    if (s.length() <= 1) return s;
    return r(s.substr(1)) + s[0];
}

Analyze the following recursive function and determine what it computes when called with s(16):
int s(int n) {
    if (n == 1) return 0;
    return 1 + s(n/2);
}

Trace the execution of recursive function t(5) and determine its output:
int t(int n) {
    if (n <= 1) return 1;
    return t(n-1) * n + t(n-2);
}

Given the recursive function below, trace u(4, 3) and determine the return value:
int u(int a, int b) {
    if (b == 0) return a;
    if (a == 0) return b;
    return u(a-1, b) + u(a, b-1) + u(a-1, b-1);
}

Trace the execution of recursive function v(6) and determine what value it returns:
int v(int n) {
    if (n <= 2) return 1;
    return v(v(n-1)) + v(n - v(n-1));
}

Analyze the following recursive function and determine what it computes when called with w(5):
int w(int n) {
    if (n <= 1) return 0;
    return (n-1) + w(n-1) + w(n-2);
}

Trace the execution of recursive function x(7) and determine its output:
int x(int n) {
    if (n <= 0) return 0;
    if (n % 2 == 0) return x(n/2) + 1;
    return x(n-1) + 2;
}

Given the recursive function below, trace y(5) and determine the return value:
int y(int n) {
    if (n <= 1) return 1;
    return y(n-1) + 2*y(n-2) + 3*y(n-3);
}

Trace the execution of recursive function z('racecar') and determine what boolean value it returns:
bool z(string s) {
    if (s.length() <= 1) return true;
    if (s[0] != s[s.length()-1]) return false;
    return z(s.substr(1, s.length()-2));
}

Analyze the following recursive function and determine what it computes when called with a(8):
int a(int n) {
    if (n <= 0) return 0;
    return n % 2 + 2 * a(n/2);
}

Trace the execution of recursive function b(5, 3) and determine its output:
int b(int n, int k) {
    if (k == 0 || k == n) return 1;
    return b(n-1, k-1) + b(n-1, k);
}

Given the recursive function below, trace c(6) and determine the return value:
int c(int n) {
    if (n <= 1) return 1;
    return c(n-1) + 2*c(n-2) - c(n-3);
}

Trace the execution of recursive function d([1,2,3,4,5], 0, 4) and determine what value it returns:
int d(int arr[], int start, int end) {
    if (start > end) return 0;
    if (start == end) return arr[start];
    int mid = (start + end) / 2;
    return d(arr, start, mid) + d(arr, mid+1, end);
}

Analyze the following recursive function and determine what it computes when called with e(13):
int e(int n) {
    if (n <= 1) return 0;
    return 1 + e(n/2) + e(n - n/2 - 1);
}
